mapper.select:
SELECT * FROM (
SELECT ROW_NUMBER() OVER( ORDER BY PO.PURCHASE_ORDER_ID DESC ) RN,
PO.PURCHASE_ORDER_ID AS purchaseOrderId, PO.STORE_ID AS storeId, S.STORE_NAME AS storeName, PO.STATUS AS status, PO.TOTAL_AMOUNT AS totalAmount, PO.ORDER_MEMO AS orderMemo, TO_CHAR( PO.CREATED_AT, 'YYYY.MM.DD' ) AS createdAt,
( SELECT MIN(POI.MATERIAL_NAME_SNAPSHOT) || ' 외 ' || (COUNT(*) - 1) || '건' FROM PURCHASE_ORDER_ITEMS POI WHERE POI.PURCHASE_ORDER_ID = PO.PURCHASE_ORDER_ID ) AS itemSummary
FROM PURCHASE_ORDERS PO JOIN STORES S ON PO.STORE_ID = S.STORE_ID
PO.STORE_ID = #{storeId}
AND PO.STATUS = #{status}
AND TRUNC(PO.CREATED_AT) >= #{startDate}
AND TRUNC(PO.CREATED_AT) <= #{endDate}
AND (
EXISTS ( SELECT 1 FROM PURCHASE_ORDER_ITEMS POI WHERE POI.PURCHASE_ORDER_ID = PO.PURCHASE_ORDER_ID AND POI.MATERIAL_NAME_SNAPSHOT LIKE '%' || #{keyword} || '%' )
OR
PO.ORDER_MEMO LIKE '%' || #{keyword} || '%'
)
)
WHERE RN BETWEEN #{startRow} AND #{endRow}

SELECT COUNT(*)
FROM PURCHASE_ORDERS PO JOIN STORES S ON PO.STORE_ID = S.STORE_ID
PO.STORE_ID = #{storeId}
AND PO.STATUS = #{status}
AND TRUNC(PO.CREATED_AT) >= #{startDate}
AND TRUNC(PO.CREATED_AT) <= #{endDate}
AND (
EXISTS ( SELECT 1 FROM PURCHASE_ORDER_ITEMS POI WHERE POI.PURCHASE_ORDER_ID = PO.PURCHASE_ORDER_ID AND POI.MATERIAL_NAME_SNAPSHOT LIKE '%' || #{keyword} || '%' )
OR
PO.ORDER_MEMO LIKE '%' || #{keyword} || '%'
)

