UPDATE PURCHASE_ORDER_ITEMS
   SET APPROVED_QUANTITY = #{approvedQuantity}
     , REJECT_REASON = #{rejectReason}
 WHERE PURCHASE_ORDER_ID = #{purchaseOrderId}
   AND MATERIAL_ID = #{materialId}

UPDATE PURCHASE_ORDERS
   SET STATUS = #{status}
 WHERE PURCHASE_ORDER_ID = #{purchaseOrderId}
